import React, { useState } from 'react';
import { Brain, Lightbulb, TrendingUp, BookOpen, Sparkles, Calendar, Tag } from 'lucide-react';

const ThinkingJourney = () => {
  const [selectedTheme, setSelectedTheme] = useState('all');
  const [selectedPeriod, setSelectedPeriod] = useState('all');

  const themes = [
    { id: 'strategy', name: '전략적 사고', icon: TrendingUp, color: 'bg-blue-500' },
    { id: 'ai', name: 'AI 전환', icon: Brain, color: 'bg-purple-500' },
    { id: 'reflection', name: '성찰과 통찰', icon: Lightbulb, color: 'bg-yellow-500' },
    { id: 'learning', name: '학습과 발전', icon: BookOpen, color: 'bg-green-500' },
    { id: 'creative', name: '창의적 사고', icon: Sparkles, color: 'bg-pink-500' }
  ];

  const documents = [
    {
      id: 1,
      title: '사고의 버전 관리: Git 명령어로 배우는 생각의 어카이빙',
      platform: 'Google Drive',
      date: '2026-01-02',
      period: 'recent',
      theme: 'creative',
      insight: '사고를 Git처럼 관리: commit(영감 박제), branch(실험적 사고), merge(통합적 통찰)',
      url: 'https://docs.google.com/document/d/1H7CLWHNirCS5AEm0SVzPL8Q9crsLm50jWgSmsZicIWY/edit',
      keyQuote: '"기록되지 않은 생각은 존재하지 않는 소프트웨어와 같다"'
    },
    {
      id: 2,
      title: '제미나이와 구글 생태계: 사고의 진보',
      platform: 'Google Drive',
      date: '2026-01-02',
      period: 'recent',
      theme: 'creative',
      insight: '단순 글쓰기를 넘어 "사고의 진보(Thought Evolution)"를 이끄는 지능형 창작 스튜디오',
      url: 'https://docs.google.com/document/d/1BDpKOa7OCPQfCZc551yw9OP_aZBDH08PKlaZHHZFk2s/edit',
      keyQuote: '"파편화된 영감을 체계적인 지성으로 진화시키는 지능형 창작 스튜디오"'
    },
    {
      id: 3,
      title: 'BCG 텍스트 기반 보고서 프레임워크',
      platform: 'Notion',
      date: '2026-01-14',
      period: 'recent',
      theme: 'strategy',
      insight: '핵심 인사이트 → 솔루션 설계 → 실행 계획의 전략적 사고 프로세스',
      url: 'https://www.notion.so/2e86b7b50b23819991ced95b43e59f8e',
      keyQuote: '"Situation → Complication → Resolution 구조로 문제의 본질 파악"'
    },
    {
      id: 4,
      title: 'EX 최적화 펄스서베이: 주간 인사이트 리포트',
      platform: 'Notion',
      date: '2026-01-05',
      period: 'recent',
      theme: 'reflection',
      insight: '주기적 데이터 수집과 인사이트 도출을 통한 조직 개선 사이클',
      url: 'https://www.notion.so/2df6b7b50b2380c59c72f832d1f16d16',
      keyQuote: '"금요일 주간 인사이트 리포트 → HRBP + 리더 브리핑"'
    },
    {
      id: 5,
      title: 'CSP 역량 개발 루틴 시스템',
      platform: 'Notion',
      date: '2025-12-27',
      period: 'recent',
      theme: 'learning',
      insight: '주 5회 콘텐츠 소비 + 주 1회 인사이트 기록의 체계적 학습 루틴',
      url: 'https://www.notion.so/2d66b7b50b2381b193a8fe79a5bb21fb',
      keyQuote: '"지속적 학습과 인사이트 축적을 통한 역량 개발"'
    },
    {
      id: 6,
      title: 'AI 솔로프레너 독서 대시보드',
      platform: 'Notion',
      date: '2025-12-19',
      period: 'earlier',
      theme: 'learning',
      insight: '독서를 통한 핵심 인사이트 추출과 지식 체계화',
      url: 'https://www.notion.so/2ce6b7b50b2381358d64db8d22868ab0',
      keyQuote: '"💎 핵심 인사이트 노트"'
    },
    {
      id: 7,
      title: '팔란티어의 AI전환',
      platform: 'Notion',
      date: '2025-11-15',
      period: 'earlier',
      theme: 'ai',
      insight: 'AI 전환의 본질: "완벽한 준비" → "즉시 실행하며 학습"으로의 사고 전환',
      url: 'https://www.notion.so/2ac6b7b50b238002a972e18f585f236d',
      keyQuote: '"근본적인 사고의 전환: 지금 바로 실제 문제를 풀면서 배우자"'
    },
    {
      id: 8,
      title: '리더십 평가 분석 리포트',
      platform: 'Notion',
      date: '2025-07-17',
      period: 'earlier',
      theme: 'strategy',
      insight: '전략적 사고/행동, 통찰력, 트렌드 센싱이 리더십의 핵심 요소',
      url: 'https://www.notion.so/2336b7b50b238028b633ebfc298c88a9',
      keyQuote: '"전략적 사고/행동(0.5861), 통찰력(0.5081), 트렌드 센싱(0.5220)"'
    },
    {
      id: 9,
      title: '데이터 리포트 상세설명 방법',
      platform: 'Notion',
      date: '2025-07-29',
      period: 'earlier',
      theme: 'reflection',
      insight: '자기 성찰, 전략적 사고/행동, 통찰력의 연계성',
      url: 'https://www.notion.so/23f6b7b50b23803d88dedd85488885a5',
      keyQuote: '"자기 성찰(80.54점) → 통찰력 → 전략적 사고/행동"'
    },
    {
      id: 10,
      title: '리더십 서베이 구조 모형',
      platform: 'Notion',
      date: '2025-06-05',
      period: 'longterm',
      theme: 'strategy',
      insight: '자기 성찰 → 통찰력 → 전략적 사고/행동의 인과 구조',
      url: 'https://www.notion.so/2096b7b50b238089a9c5e27be7c885e7',
      keyQuote: '"[자기 성찰] → [통찰력] → [전략적 사고/행동]"'
    },
    {
      id: 11,
      title: '다이어그램: 사고/학습 전략',
      platform: 'Notion',
      date: '2025-06-09',
      period: 'longterm',
      theme: 'learning',
      insight: '전략사고 → 커뮤니케이션/결단 → 학습/통찰의 순환 구조',
      url: 'https://www.notion.so/20a6b7b50b2380c78124ecab6e919d1a',
      keyQuote: '"2단계: 사고/학습 전략사고 → 커뮤니케이션/결단 → 학습/통찰"'
    }
  ];

  const periods = [
    { id: 'all', name: '전체 기간', color: 'bg-gray-500' },
    { id: 'recent', name: '최근 (2025.12~)', color: 'bg-indigo-500' },
    { id: 'earlier', name: '중기 (2025.06~11)', color: 'bg-teal-500' },
    { id: 'longterm', name: '장기 (2025.06 이전)', color: 'bg-amber-500' }
  ];

  const filteredDocs = documents.filter(doc => {
    const themeMatch = selectedTheme === 'all' || doc.theme === selectedTheme;
    const periodMatch = selectedPeriod === 'all' || doc.period === selectedPeriod;
    return themeMatch && periodMatch;
  });

  const ThemeIcon = ({ theme }) => {
    const themeConfig = themes.find(t => t.id === theme);
    if (!themeConfig) return null;
    const Icon = themeConfig.icon;
    return <Icon className="w-5 h-5" />;
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 p-8">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <div className="flex items-center justify-center gap-3 mb-4">
            <Brain className="w-12 h-12 text-purple-400" />
            <h1 className="text-5xl font-bold text-white">사고의 여정</h1>
          </div>
          <p className="text-xl text-purple-200">당신의 중요한 순간들, 통찰과 전환의 기록</p>
          <div className="mt-4 flex items-center justify-center gap-2 text-purple-300">
            <Calendar className="w-5 h-5" />
            <span>{filteredDocs.length}개의 사고 기록</span>
          </div>
        </div>

        {/* Filters */}
        <div className="bg-white/10 backdrop-blur-lg rounded-2xl p-6 mb-8 border border-white/20">
          <div className="grid md:grid-cols-2 gap-6">
            {/* Theme Filter */}
            <div>
              <label className="text-white font-semibold mb-3 block flex items-center gap-2">
                <Tag className="w-5 h-5" />
                테마별 탐색
              </label>
              <div className="flex flex-wrap gap-2">
                <button
                  onClick={() => setSelectedTheme('all')}
                  className={`px-4 py-2 rounded-lg font-medium transition-all ${
                    selectedTheme === 'all'
                      ? 'bg-white text-purple-900 shadow-lg scale-105'
                      : 'bg-white/20 text-white hover:bg-white/30'
                  }`}
                >
                  전체
                </button>
                {themes.map(theme => (
                  <button
                    key={theme.id}
                    onClick={() => setSelectedTheme(theme.id)}
                    className={`px-4 py-2 rounded-lg font-medium transition-all flex items-center gap-2 ${
                      selectedTheme === theme.id
                        ? `${theme.color} text-white shadow-lg scale-105`
                        : 'bg-white/20 text-white hover:bg-white/30'
                    }`}
                  >
                    <theme.icon className="w-4 h-4" />
                    {theme.name}
                  </button>
                ))}
              </div>
            </div>

            {/* Period Filter */}
            <div>
              <label className="text-white font-semibold mb-3 block flex items-center gap-2">
                <Calendar className="w-5 h-5" />
                시간별 탐색
              </label>
              <div className="flex flex-wrap gap-2">
                {periods.map(period => (
                  <button
                    key={period.id}
                    onClick={() => setSelectedPeriod(period.id)}
                    className={`px-4 py-2 rounded-lg font-medium transition-all ${
                      selectedPeriod === period.id
                        ? `${period.color} text-white shadow-lg scale-105`
                        : 'bg-white/20 text-white hover:bg-white/30'
                    }`}
                  >
                    {period.name}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Documents Grid */}
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredDocs.map(doc => {
            const themeConfig = themes.find(t => t.id === doc.theme);
            return (
              <a
                key={doc.id}
                href={doc.url}
                target="_blank"
                rel="noopener noreferrer"
                className="group bg-white/10 backdrop-blur-lg rounded-xl p-6 border border-white/20 hover:border-white/40 hover:bg-white/15 transition-all hover:scale-105 hover:shadow-2xl cursor-pointer"
              >
                <div className="flex items-start justify-between mb-3">
                  <div className={`p-3 rounded-lg ${themeConfig.color} group-hover:scale-110 transition-transform`}>
                    <ThemeIcon theme={doc.theme} />
                  </div>
                  <span className="text-xs text-purple-300 bg-purple-900/50 px-2 py-1 rounded">
                    {doc.platform}
                  </span>
                </div>

                <h3 className="text-white font-bold text-lg mb-2 line-clamp-2 group-hover:text-purple-200">
                  {doc.title}
                </h3>

                <p className="text-purple-200 text-sm mb-3 line-clamp-3">
                  {doc.insight}
                </p>

                <div className="bg-purple-900/30 rounded-lg p-3 mb-3 border-l-4 border-purple-400">
                  <p className="text-purple-100 text-xs italic line-clamp-2">
                    {doc.keyQuote}
                  </p>
                </div>

                <div className="flex items-center justify-between text-xs text-purple-300">
                  <span>{doc.date}</span>
                  <span className="group-hover:text-white transition-colors">
                    읽어보기 →
                  </span>
                </div>
              </a>
            );
          })}
        </div>

        {filteredDocs.length === 0 && (
          <div className="text-center py-16">
            <Lightbulb className="w-16 h-16 text-purple-400 mx-auto mb-4 opacity-50" />
            <p className="text-purple-200 text-lg">선택한 필터에 해당하는 문서가 없습니다</p>
          </div>
        )}

        {/* Summary Stats */}
        <div className="mt-12 bg-white/10 backdrop-blur-lg rounded-2xl p-8 border border-white/20">
          <h2 className="text-2xl font-bold text-white mb-6 flex items-center gap-3">
            <Sparkles className="w-8 h-8 text-yellow-400" />
            핵심 인사이트 패턴
          </h2>
          <div className="grid md:grid-cols-3 gap-6">
            <div className="bg-purple-900/30 rounded-xl p-6 border border-purple-500/30">
              <h3 className="text-purple-300 font-semibold mb-3">사고의 구조</h3>
              <p className="text-white text-sm leading-relaxed">
                자기 성찰 → 통찰력 → 전략적 사고/행동의 순환 구조가 반복적으로 나타남
              </p>
            </div>
            <div className="bg-blue-900/30 rounded-xl p-6 border border-blue-500/30">
              <h3 className="text-blue-300 font-semibold mb-3">실행 철학</h3>
              <p className="text-white text-sm leading-relaxed">
                "완벽한 준비" 대신 "즉시 실행하며 학습"하는 AI 시대의 사고방식 전환
              </p>
            </div>
            <div className="bg-pink-900/30 rounded-xl p-6 border border-pink-500/30">
              <h3 className="text-pink-300 font-semibold mb-3">체계적 관리</h3>
              <p className="text-white text-sm leading-relaxed">
                사고를 버전 관리하듯 기록하고, 실험하고, 통합하는 시스템적 접근
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ThinkingJourney;

